import requests
from azure.identity import DefaultAzureCredential

def audit_billing_profile_health(billing_account_name: str) -> list:
    credential = DefaultAzureCredential()
    token = credential.get_token("https://management.azure.com/.default").token
    headers = {"Authorization": f"Bearer {token}"}

    url = (
        f"https://management.azure.com/providers/Microsoft.Billing/"
        f"billingAccounts/{billing_account_name}/billingProfiles"
        f"?api-version=2020-05-01"
    )
    resp = requests.get(url, headers=headers)

    unhealthy = []
    for profile in resp.json().get("value", []):
        props = profile.get("properties", {})
        status = props.get("status", "Active")
        if status != "Active":
            unhealthy.append({
                "name": profile["name"],
                "display_name": props.get("displayName"),
                "status": status,
                "status_reason": props.get("statusReasonCode", "Unknown"),
                "spending_limit": props.get("spendingLimit"),
                "currency": props.get("currency"),
            })

    return unhealthy

issues = audit_billing_profile_health("<billing-account-id>")
if issues:
    for p in issues:
        print(
            f"ALERT: Profile '{p['display_name']}' ({p['name']}) "
            f"status={p['status']} reason={p['status_reason']}"
        )
else:
    print("All billing profiles are Active")
